#result {
    margin-top: 20px;
}

svg {
    max-width: 100%;
    height: auto;
    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
}

document.addEventListener('DOMContentLoaded', () => {
    const form = document.getElementById('input-form');
    const input = document.getElementById('input-word');
    const generateBtn = document.getElementById('generate-btn');
    const resultDiv = document.getElementById('result');
    const errorDiv = document.getElementById('error');

    form.addEventListener('submit', async (e) => {
        e.preventDefault();
        const inputWord = input.value.trim();

        if (!inputWord) {
            showError('請輸入一個漢語詞彙');
            return;
        }

        generateBtn.disabled = true;
        generateBtn.textContent = '生成中...';
        errorDiv.textContent = '';

        try {
            const response = await fetch('/generate', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ input: inputWord }),
            });

            const data = await response.json();

            if (response.ok) {
                const svgCard = generateSVG(inputWord, data.explanation);
                resultDiv.innerHTML = svgCard;
            } else {
                showError(data.error || '生成解釋時發生錯誤');
            }
        } catch (error) {
            showError('網絡錯誤，請稍後再試');
        } finally {
            generateBtn.disabled = false;
            generateBtn.textContent = '生成新解';
        }
    });

    function showError(message) {
        errorDiv.textContent = message;
    }

    function generateSVG(input, explanation) {
        const width = 400;
        const height = 600;
        const margin = 20;
        const background = 'rgb(240, 234, 214)';
        const text = 'rgb(74, 74, 74)';
        const accent = 'rgb(180, 36, 28)';

        return `
            <svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
                <rect width="100%" height="100%" fill="${background}"/>
                <text x="${width/2}" y="${margin*2}" font-family="Arial, sans-serif" font-size="24" fill="${accent}" text-anchor="middle">漢語新解</text>
                <line x1="${margin}" y1="${margin*2.5}" x2="${width-margin}" y2="${margin*2.5}" stroke="${accent}" stroke-width="2"/>
                <text x="${margin}" y="${margin*4}" font-family="Arial, sans-serif" font-size="18" fill="${text}">${input}</text>
                <foreignObject x="${margin}" y="${margin*5}" width="${width-margin*2}" height="${height-margin*6}">
                    <p xmlns="http://www.w3.org/1999/xhtml" style="font-family: Arial, sans-serif; font-size: 16px; color: ${text};">
                        ${explanation}
                    </p>
                </foreignObject>
            </svg>
        `;
    }
});
